+            format!("\x1b]8;;{url}\x1b\\{text}\x1b]8;;\x1b\\")
+        } else if self.is_plain() || self.is_json() {
+            if text == url {
+                text.to_string()
+            } else {
+                format!("{text} ({url})")
+            }
+        } else {
+            // Rich mode but no hyperlink support - just show text
+            text.to_string()
+        }
+    }
