+    #[must_use]
+    pub fn format_file_hyperlink(&self, text: &str, path: &std::path::Path) -> String {
+        if self.supports_hyperlinks {
+            let abs_path = if path.is_absolute() {
+                path.to_path_buf()
+            } else {
+                std::env::current_dir()
+                    .unwrap_or_default()
+                    .join(path)
+            };
+            let url = format!("file://{}", abs_path.display());
+            self.format_hyperlink(text, &url)
+        } else {
+            text.to_string()
+        }
+    }
